codeChallenges.codigoSeguro:
// Validación robusta de contraseña
function validatePassword(password) {
  const checks = [
    password.length >= 12,
    /[A-Z]/.test(password),
    /[a-z]/.test(password),
    /[0-9]/.test(password),
    /[^A-Za-z0-9]/.test(password),
    !/(.)\1{2,}/.test(password),
  ];
  return checks.every(Boolean);
}

